dataSet.query:
ВЫБРАТЬ РАЗРЕШЕННЫЕ Деньги.Ссылка КАК Документ, Деньги.Дата КАК Дата, Деньги.Номер КАК Номер, Деньги.Сумма КАК СуммаДокумента, Деньги.Валюта КАК Валюта, Деньги.Контрагент КАК Контрагент, Деньги.ХозяйственнаяОперация КАК ВидОперации, Деньги.Организация КАК Организация, Деньги.Тип КАК ТипДокумента, ВЫБОР КОГДА Деньги.ПометкаУдаления = ИСТИНА ТОГДА 2 КОГДА Деньги.Проведен = ИСТИНА ТОГДА 1 ИНАЧЕ 0 КОНЕЦ КАК СостояниеДокумента, 1 КАК ЗаполнениеАналитик, ЛОЖЬ КАК Пометка ПОМЕСТИТЬ Деньги ИЗ ЖурналДокументов.бит_ОтраженияФактаДДС КАК Деньги ГДЕ Деньги.Дата МЕЖДУ &НачалоПериода И &ОкончаниеПериода И Деньги.Проведен ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ РАЗРЕШЕННЫЕ Деньги.Документ КАК Документ, ОборотыПоБюджетам.СтатьяОборотов КАК СтатьяОборотов, ОборотыПоБюджетам.Сумма КАК Сумма ПОМЕСТИТЬ ОборотыПоБюджетамПредварительная ИЗ Деньги КАК Деньги ВНУТРЕННЕЕ СОЕДИНЕНИЕ РегистрНакопления.бит_ОборотыПоБюджетам КАК ОборотыПоБюджетам ПО Деньги.Документ = ОборотыПоБюджетам.Регистратор И (ОборотыПоБюджетам.ТипЗаписи <> ЗНАЧЕНИЕ(Перечисление.бит_ТипыЗаписейОборотовПоБюджетам.ЗависимыйОборот)) И (ОборотыПоБюджетам.ТипЗаписи <> ЗНАЧЕНИЕ(Перечисление.бит_ТипыЗаписейОборотовПоБюджетам.Перевод)) ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ОборотыПоБюджетамПредварительная.Документ КАК Документ, ВЫБОР КОГДА ОборотыПоБюджетамПредварительная.Документ ССЫЛКА Документ.ПриходныйКассовыйОрдер ТОГДА ВЫРАЗИТЬ(ОборотыПоБюджетамПредварительная.Документ КАК Документ.ПриходныйКассовыйОрдер).ХозяйственнаяОперация ИНАЧЕ ВЫРАЗИТЬ(ОборотыПоБюджетамПредварительная.Документ КАК Документ.РасходныйКассовыйОрдер).ХозяйственнаяОперация КОНЕЦ КАК ВидОперации, ОборотыПоБюджетамПредварительная.СтатьяОборотов КАК СтатьяОборотов ПОМЕСТИТЬ ВидыОпераций ИЗ ОборотыПоБюджетамПредварительная КАК ОборотыПоБюджетамПредварительная ГДЕ (ОборотыПоБюджетамПредварительная.Документ ССЫЛКА Документ.ПриходныйКассовыйОрдер ИЛИ ОборотыПоБюджетамПредварительная.Документ ССЫЛКА Документ.РасходныйКассовыйОрдер) ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ВидыОпераций.Документ КАК Документ, ВидыОпераций.ВидОперации КАК ВидОперации, ВидыОпераций.СтатьяОборотов КАК СтатьяОборотов ПОМЕСТИТЬ ИсключаемыеДвижения ИЗ ВидыОпераций КАК ВидыОпераций ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.бит_СтатьиОборотов КАК СтатьиОборотов ПО ВидыОпераций.СтатьяОборотов = СтатьиОборотов.Ссылка И (ВидыОпераций.ВидОперации В (&ВидыОперацийДвойныхПроводок)) И (СтатьиОборотов.РасходДоход = ЗНАЧЕНИЕ(Перечисление.бит_РасходДоход.Расходование)) ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ОборотыПоБюджетамПредварительная.Документ КАК Документ, ВЫБОР КОГДА СУММА(ОборотыПоБюджетамПредварительная.Сумма) < 0 ТОГДА -1 ИНАЧЕ 1 КОНЕЦ * СУММА(ОборотыПоБюджетамПредварительная.Сумма) КАК Сумма ПОМЕСТИТЬ ОборотыПоБюджетам ИЗ ОборотыПоБюджетамПредварительная КАК ОборотыПоБюджетамПредварительная ЛЕВОЕ СОЕДИНЕНИЕ ИсключаемыеДвижения КАК ИсключаемыеДвижения ПО ОборотыПоБюджетамПредварительная.Документ = ИсключаемыеДвижения.Документ И ОборотыПоБюджетамПредварительная.СтатьяОборотов = ИсключаемыеДвижения.СтатьяОборотов ГДЕ ИсключаемыеДвижения.СтатьяОборотов ЕСТЬ NULL
СГРУППИРОВАТЬ ПО ОборотыПоБюджетамПредварительная.Документ ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ РАЗРЕШЕННЫЕ Деньги.Документ КАК Документ, МАКСИМУМ(НЕ СоответствиеЗаписейТрансляции.Регистратор ЕСТЬ NULL) КАК ИспользуетсяТрансляция ПОМЕСТИТЬ Трансляция ИЗ Деньги КАК Деньги ЛЕВОЕ СОЕДИНЕНИЕ РегистрСведений.бит_СоответствиеЗаписейТрансляции КАК СоответствиеЗаписейТрансляции ВНУТРЕННЕЕ СОЕДИНЕНИЕ Справочник.бит_ОбъектыСистемы КАК бит_ОбъектыСистемы ПО СоответствиеЗаписейТрансляции.Приемник = бит_ОбъектыСистемы.Ссылка И (бит_ОбъектыСистемы.ИмяОбъекта = "бит_ОборотыПоБюджетам") ПО Деньги.Документ = СоответствиеЗаписейТрансляции.Регистратор
СГРУППИРОВАТЬ ПО Деньги.Документ ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ Деньги.Документ КАК Документ, Деньги.Дата КАК Дата, Деньги.Номер КАК Номер, Деньги.Валюта КАК Валюта, Деньги.Контрагент КАК Контрагент, Деньги.ВидОперации КАК ВидОперации, Деньги.Организация КАК Организация, Деньги.ТипДокумента КАК ТипДокумента, Трансляция.ИспользуетсяТрансляция КАК ИспользуетсяТрансляция, Деньги.СостояниеДокумента КАК СостояниеДокумента, Деньги.ЗаполнениеАналитик КАК ЗаполнениеАналитик, Деньги.Пометка КАК Пометка, ОборотыПоБюджетам.Сумма КАК СуммаБюджет, Деньги.СуммаДокумента КАК СуммаДокумента ИЗ Деньги КАК Деньги ВНУТРЕННЕЕ СОЕДИНЕНИЕ ОборотыПоБюджетам КАК ОборотыПоБюджетам ПО Деньги.Документ = ОборотыПоБюджетам.Документ ЛЕВОЕ СОЕДИНЕНИЕ Трансляция КАК Трансляция ПО Деньги.Документ = Трансляция.Документ ГДЕ (&ВсеПозиции ИЛИ Деньги.СуммаДокумента <> ОборотыПоБюджетам.Сумма)
